#!/usr/bin/env python3
"""Materialize the reviewed MLB recovery shadow runtime and tests."""
from __future__ import annotations
import base64
import gzip
from pathlib import Path

FILES = {
    "hello_world/mlb_recovery_shadow_v1.py": "",
    "tests/unit/test_mlb_recovery_shadow_v1.py": "",
}

for raw_path, payload in FILES.items():
    path = Path(raw_path)
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_bytes(gzip.decompress(base64.b64decode(payload)))
    print(f"materialized {path} ({path.stat().st_size} bytes)")
